import{_ as o,o as r,c as e,ae as a}from"./chunks/framework.6gkcVjOI.js";const u=JSON.parse('{"title":"概述","description":"什么是 claude-code-Go？了解这个 Go 实现的 Claude Code 及其核心功能","frontmatter":{"title":"概述","description":"什么是 claude-code-Go？了解这个 Go 实现的 Claude Code 及其核心功能"},"headers":[],"relativePath":"zh/guide/introduction.md","filePath":"zh/guide/introduction.md","lastUpdated":1775199659000}'),d={name:"zh/guide/introduction.md"};function l(i,t,n,s,h,c){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>欢迎了解 claude-code-Go，这是一个用 Go 实现的 Anthropic Claude Code（Cline）智能体系统。</p><h2 id="什么是-claude-code-go" tabindex="-1">什么是 claude-code-Go？ <a class="header-anchor" href="#什么是-claude-code-go" aria-label="Permalink to &quot;什么是 claude-code-Go？&quot;">​</a></h2><p>claude-code-Go 是一个终端驱动的 AI 编程助手，它将 Claude Code 强大的智能体能力带入 Go 生态系统。它完整实现了智能体循环，包含内置工具、权限系统、MCP（Model Context Protocol）支持以及 SSE（Server-Sent Events）流式输出。</p><p>你可以把它想象成一个 AI 编程伙伴，能够：</p><ul><li>读取、编写和编辑项目中的文件</li><li>执行 shell 命令来运行构建、测试或脚本</li><li>使用 glob 模式和内容搜索来浏览代码库</li><li>在终端 REPL 中与你交互式地协作</li></ul><h2 id="它和普通聊天机器人有什么不同" tabindex="-1">它和普通聊天机器人有什么不同？ <a class="header-anchor" href="#它和普通聊天机器人有什么不同" aria-label="Permalink to &quot;它和普通聊天机器人有什么不同？&quot;">​</a></h2><p>与传统的聊天机器人不同，claude-code-Go 作为一个具有自主能力和工具使用能力的<strong>智能体</strong>运作。</p><table tabindex="0"><thead><tr><th>特性</th><th>聊天机器人</th><th>claude-code-Go</th></tr></thead><tbody><tr><td><strong>交互模式</strong></td><td>请求-响应</td><td>持续智能体循环，调用工具</td></tr><tr><td><strong>能力</strong></td><td>仅文本生成</td><td>读取、编写、编辑、执行、搜索文件</td></tr><tr><td><strong>状态管理</strong></td><td>无状态</td><td>消息历史 + 上下文压缩</td></tr><tr><td><strong>用户控制</strong></td><td>被动接收</td><td>危险操作需主动审批</td></tr><tr><td><strong>使用场景</strong></td><td>问答、对话</td><td>代码开发、自动化</td></tr></tbody></table><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><p>claude-code-Go 遵循最小依赖的原则构建：</p><table tabindex="0"><thead><tr><th>组件</th><th>技术</th></tr></thead><tbody><tr><td><strong>编程语言</strong></td><td>Go 1.23+</td></tr><tr><td><strong>标准库</strong></td><td>仅使用 Go 标准库（主二进制无外部依赖）</td></tr><tr><td><strong>Python 测试框架</strong></td><td>可选（用于测试、模拟、评估）</td></tr><tr><td><strong>API</strong></td><td>Anthropic Messages API + SSE 流式传输</td></tr></tbody></table><p><code>harness/</code> 目录下的 Python 测试框架是可选的，提供：</p><ul><li>模拟 API 服务器（测试时无需 API 费用）</li><li>会话回放（用于调试）</li><li>质量评估器（用于集成测试）</li></ul><h2 id="核心数字" tabindex="-1">核心数字 <a class="header-anchor" href="#核心数字" aria-label="Permalink to &quot;核心数字&quot;">​</a></h2><ul><li><strong>约 31</strong> 个 Go 源文件（非测试）</li><li><strong>约 4,000</strong> 行 Go 代码</li><li><strong>约 2,000</strong> 行 Python 代码（harness）</li><li><strong>8</strong> 个内部模块</li><li><strong>6</strong> 个内置工具（Read、Write、Edit、Glob、Grep、Bash）</li></ul><h2 id="你将学到什么" tabindex="-1">你将学到什么 <a class="header-anchor" href="#你将学到什么" aria-label="Permalink to &quot;你将学到什么&quot;">​</a></h2><p>本文档涵盖 claude-code-Go 的架构和实现细节：</p><ol><li><strong>AI 智能体架构</strong> — 智能体循环如何工作、决策过程和工具选择</li><li><strong>流式 API 集成</strong> — 从 Anthropic API 进行 SSE token 流式传输，实现实时输出</li><li><strong>工具系统</strong> — 内置工具 + MCP 集成，扩展能力</li><li><strong>安全设计</strong> — 三层权限系统，控制危险操作</li><li><strong>工程实践</strong> — 结构化日志、优雅关闭、配置管理</li></ol><h2 id="目标读者" tabindex="-1">目标读者 <a class="header-anchor" href="#目标读者" aria-label="Permalink to &quot;目标读者&quot;">​</a></h2><p>本文档面向：</p><ul><li>对构建 AI 驱动工具感兴趣的 <strong>Go 开发者</strong></li><li>对智能体架构好奇的 <strong>系统程序员</strong></li><li>寻求 CLI 自动化与 AI 能力的 <strong>DevOps 工程师</strong></li><li>探索 LLM 应用模式的 <strong>研究人员</strong></li></ul><p>你需要熟悉：</p><ul><li>Go 编程语言基础</li><li>终端/命令行界面</li><li>HTTP API 和 JSON 数据格式</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>准备好开始了吗？前往<a href="./quick-start.html">快速开始</a>指南运行你的第一个命令。</p><p>或者深入了解<a href="./../architecture/overview.html">架构概览</a>，理解各个部分如何协同工作。</p>',27)])])}const p=o(d,[["render",l]]);export{u as __pageData,p as default};
